INSERT INTO public.photos VALUES (22873, 'Paseo de Cu‚îú¬Ællar 1987', 'Luis M‚îú¬°nguez. 1987. Desde la torre del cementerio erigido a la memoria de los fascistas italianos que murieron en Espa‚îú‚ñía entre 1936-39, un limpio vistazo al lado norte de este "observatorio romano". A la izquierda, antes de su remodelaci‚îú‚îÇn, la vivienda unifamiliar atribuida a Luis de la Figuera, en formas modernistas de comienzos del s.XX. Al otro lado de Maestro Estremiana, los antiguos dep‚îú‚îÇsitos de agua de Pignatelli, funcionales. Bajando el abrupto desnivel, a su derecha, la masa arb‚îú‚îÇrea del Parque de Pignatelli, y la cortina no menos densa de bloques de viviendas del paseo de Cu‚îú¬Ællar levantados durante el desarrollismo.', 1987, 1987, 1987, 'Anos 80', 'TORRERO', 41.63469100, -0.88530900, '0101000020E6100000C5573B8A7354ECBF6308008E3DD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15838836972.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15838836972.webp', 'https://www.flickr.com/photos/zaragozaantigua/15838836972/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22881, 'Calle Royo Villanova 1985', 'Captura del estado de la calle Royo Villanova, cuando a‚îú‚ïën estaban en pie las parcelas del "Molino Rosa" (a la izquierda), que marcaban entonces el final de la Avenida S. Jos‚îú¬Æ. Entre las casas y los coches aparcados bajaba al aire la acequia que desde el Canal Imperial abastec‚îú¬°a de agua a los ingenios fabriles de la zona, de los que ya s‚îú‚îÇlo exist‚îú¬°a el de la harinera SAPASA, un poquito m‚îú√≠s abajo. A la derecha, otras construcciones de los cuarenta donde hoy se levanta el reciente bloque n‚î¨‚ïë 15 de la calle, y m‚îú√≠s abajo, el solar de la antigua F‚îú√≠brica Pina. En la prensa del momento el tratamiento informativo a todo esto ten‚îú¬°a aires casi po‚îú¬Æticos: "Barranco, torrentera, c‚îú√≠rcava o tobog‚îú√≠n de tierra, por donde el ‚îú‚ïëltimo intr‚îú¬Æpido que se atrevi‚îú‚îÇ a bajar volc‚îú‚îÇ y tuvo que sacarlo la gr‚îú‚ïëa. La calle Royo Villanova presenta un aspecto deplorable, como si fuera una rendija de la ciudad, que alguien se hubiese olvidado de dibujarla y que, seg‚îú‚ïën parece, a‚îú‚ïën tardar‚îú√≠ en hacerlo. Este trozo, situado en la parte alta del barrio de S. Jos‚îú¬Æ, clama al cielo para que lo arreglen" (El D‚îú¬°a, 17-02-1985). No hace tanto tiempo. O s‚îú¬°. Fuente visual: AVV San Jos‚îú¬Æ', 1985, 1985, 1985, 'Anos 80', 'TORRERO', 41.63404000, -0.88069700, '0101000020E610000013EE9579AB2EECBF8C2D043928D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19630980703.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19630980703.webp', 'https://www.flickr.com/photos/zaragozaantigua/19630980703/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23136, 'Harinera de San Jos‚îú¬Æ 2006', 'Foto: Miriam Mart‚îú¬°nez. Vista de la manzana entre la avenida de San Jos‚îú¬Æ y la calle de Luis Royo Villanova, con el parque de la Memoria a la derecha. En el centro, edificio de la Harinera de San Jos‚îú¬Æ, inaugurada en 1880. Tras su adquisici‚îú‚îÇn en 1900 por Antonio Mor‚îú‚îÇn, fue ampliada en 1920, y estuvo en servicio hasta los a‚îú‚ñíos ochenta. En 2006 comenz‚îú‚îÇ la primera fase de las obras de acondicionamiento, que se prolong‚îú‚îÇ hasta 2008. En 2015, se realizaron nuevos retoques y se abri‚îú‚îÇ parcialmente como centro cultural en 2016. Fuente: Heraldo de Arag‚îú‚îÇn.', 2006, 2006, 2006, 'Siglo XXI', 'TORRERO', 41.63460600, -0.88050600, '0101000020E61000001CD13DEB1A2DECBF35ECF7C43AD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31807207771.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31807207771.webp', 'https://www.flickr.com/photos/zaragozaantigua/31807207771/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23253, 'La Balseta c.1923', 'El lavadero √î√á¬£La Balseta√î√á√ò (balsa de agua peque‚îú‚ñía) formaba parte de las intervenciones realizadas gracias a la llegada de agua por el Canal Imperial, a finales del siglo XVIII. Alimentado por la acequia de √î√á¬£El Plano√î√á√ò, que tomaba agua en la Almenara de Santa Engracia, esta instalaci‚îú‚îÇn cumpl‚îú¬°a la importante funci‚îú‚îÇn de servir de lavadero de ropa para las viviendas del entorno, ubicadas entre el Canal y el √î√á¬£Camino que conduce a Torrero√î√á√ò. La progresiva urbanizaci‚îú‚îÇn de la zona, el aumento de poblaci‚îú‚îÇn, y la ausencia de abastecimiento de agua hasta bien entrado el siglo XX, hizo que este lavadero se convirtiera en un espacio de referencia para la zona alta del barrio de San Jos‚îú¬Æ durante varias generaciones. Dise‚îú‚ñíado sin techumbre, ya avanzado el siglo XX fue cubierto con mamposter‚îú¬°a y teja. Fue el ‚îú‚ïëltimo lavadero urbano en activo de la ciudad, hasta que la generalizaci‚îú‚îÇn del abastecimiento de agua para uso dom‚îú¬Æstico lo fue dejando sin usuarias (lavar la ropa era √î√á¬£cosa de mujeres√î√á√ò). Se dej‚îú‚îÇ degradar hasta que fue derribado por viejo, molesto e in‚îú‚ïëtil, al comienzo de la d‚îú¬Æcada de los a‚îú‚ñíos 70. A‚îú‚ñíos despu‚îú¬Æs, cuando este tramo de la Avenida de San Jos‚îú¬Æ fue intervenido, se dise‚îú‚ñí‚îú‚îÇ una √î√á¬£Glorieta de la Balseta√î√á√ò, con un estanque de agua y una escultura en bronce (obra de Manuel Arc‚îú‚îÇn) que representa a una "Lavandera", como recuerdo de su existencia. En la imagen, el original lavadero prestando servicio. Una de las parcelitas del fondo, aunque parezca incre‚îú¬°ble, sobrevive, aunque deshabitada, espectante. Fuente visual: Miguel Faci Abad.', 1923, 1923, 1923, 'Anos 20', 'TORRERO', 41.63428900, -0.88155600, '0101000020E610000062F6B2EDB435ECBF359BC76130D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20124932749.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20124932749.webp', 'https://www.flickr.com/photos/zaragozaantigua/20124932749/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23255, 'La Balseta c.1923', 'Foto: Jes‚îú‚ïës Corm‚îú√≠n. Imagen del lavadero p‚îú‚ïëblico denominado "La Balseta" arriba del todo del Camino de San Jos‚îú¬Æ, una reliquia dieciochesca de una utilidad plurisecular. Un tiempo despu‚îú¬Æs ser‚îú√≠ cubierto con un octogonal tejadillo que le permitir‚îú√≠ resistir hasta su demolici‚îú‚îÇn a comienzos de los prodigiosos a‚îú‚ñíos 70 del pasado siglo, por dar mala imagen a una ciudad tan moderna como esta misma. Mientras las mujeres faenan la ropa y observan al ojo indiscreto, a la izquierda quedan las tapias de las parcelas del camino de San Fernando, por donde desciende la acequia del Plano que abastece este lugar de agua canalina. A la derecha, las viviendas e instalaciones del "Molino Rosa", con una casa de vinos y de comer en los bajos. Fuente visual: Cr‚îú‚îÇnica de Zaragoza 1900-1920.', 1923, 1923, 1923, 'Anos 20', 'TORRERO', 41.63428900, -0.88155600, '0101000020E610000062F6B2EDB435ECBF359BC76130D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20537578002.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20537578002.webp', 'https://www.flickr.com/photos/zaragozaantigua/20537578002/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23259, 'Puerto de Miraflores 1794', '"Plano que manifiesta todas las obras construidas, y proyectadas, en el Monte Torrero", dibujado por Tiburcio del Caso. Once a‚îú‚ñíos despu‚îú¬Æs del primer vuelo tripulado por humanos (Paris, 1783), el empleo de esta herramienta en las representaciones cartogr‚îú√≠ficas no ser‚îú¬°a realidad hasta que un fot‚îú‚îÇgrafo ("Nadar", en Clamart, Hauts-de-Seine) captur‚îú‚îÇ la primera fotograf‚îú¬°a a‚îú¬Ærea conocida, si bien no se conserva. Hasta entonces, los levantamientos topogr‚îú√≠ficos eran de pocos vuelos, pero los avances cient‚îú¬°ficos y su aplicaci‚îú‚îÇn a esta disciplina lograron un acercamiento gr‚îú√≠fico a la realidad m‚îú√≠s que satisfactorio. Este plano est‚îú√≠ asociado al acontecimiento de la llegada de aguas a trav‚îú¬Æs del Canal Imperial, que a finales del siglo XVIII, abri‚îú‚îÇ una nueva etapa en la historia de la ciudad. Ilumina las posibilidades previstas para el entorno del complejo denominado "Puerto de Miraflores", con infraestructuras suficientes para garantizar la navegaci‚îú‚îÇn de mercanc‚îú¬°as, abastos y personas. A la izquierda queda la almenara de Santa Engracia, de donde nace la nueva acequia de El Plano. El nuevo puente de Am‚îú¬Ærica vertebra y da consistencia al acceso al monte de Torrero. La almenara de Pignatelli, a la derecha, deriva agua a la acequia de Entonar. En las espectaculares instalaciones portuarias del centro de la imagen, a ambos lados del Canal, estaba incluida la iglesia parroquial y civil de San Fernando, y ya queda constancia de la existencia de un lavadero circular alimentado por la acequia de El Plano, antes de seguir hacia abajo por la enorme pendiente del camino que sube a Torrero. All‚îú¬°, tres instalaciones fabriles fueron proyectadas en su parte alta para aprovechar la energ‚îú¬°a del agua en descenso: un molino harinero, un molino de aceite, y una f‚îú√≠brica de aguardiente. Tiempos de Ilustraci‚îú‚îÇn, de so‚îú‚ñíar, aun con los pies en el suelo. Fuente visual: "Descripci‚îú‚îÇn del Canal Imperial de Arag‚îú‚îÇn" por el marqu‚îú¬Æs de Aguilar, 1794.', 1794, 1794, 1794, 'Siglo XIX', 'TORRERO', 41.63304000, -0.88264900, '0101000020E61000007A1B9B1DA93EECBFA987687407D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25101491066.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25101491066.webp', 'https://www.flickr.com/photos/zaragozaantigua/25101491066/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23263, 'La Balseta 1923', 'Imagen del entorno del lavadero P‚îú‚ïëblico de la Balseta, con un grupo de mujeres utiliz‚îú√≠ndolo a la derecha. Inmediato, el cauce al aire de la acequia del Plano que lo alimentaba con agua del Canal Imperial derivada mediante la almenara de Santa Engracia. A la izquierda, muros de las ilustradas dependencias canalinas que albergaron los hornos de cocer pan y tahona de yeso del Canal Imperial. En la fotograf‚îú¬°a se puede apreciar el punto donde se derivaba agua hasta el lavadero. A la derecha e inmediato, puentecillo de piedras que salvaba la caudalosa acequia y daba acceso al ‚îú‚ïëltimo tramo del camino de San Jos‚îú¬Æ, que hacia la derecha, y en pronunciado descenso, bajaba junto a la harinera de Antonio Mor‚îú‚îÇn. Al fondo y a la derecha, tras las parcelas recayentes a la calle de Lapuyade se puede ver la c‚îú‚ïëpula de Santiago, antiguo convento de San Ildefonso.', 1923, 1923, 1923, 'Anos 20', 'TORRERO', 41.63425700, -0.88169500, '0101000020E6100000BB7EC16ED836ECBF292158552FD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51370791814.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51370791814.webp', 'https://www.flickr.com/photos/zaragozaantigua/51370791814/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23351, 'Playa de Torrero a‚îú‚ñíos 30', 'AHPZ-Archivo Fotogr‚îú√≠fico Jos‚îú¬Æ Galiay, (SF). Canal Imperial. Playa de Torrero, Dique de carena y Puente de Am‚îú¬Ærica.', 1930, 1930, 1939, 'Anos 30', 'TORRERO', 41.63307000, -0.88480700, '0101000020E61000002DB308C55650ECBF130A117008D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14887539445.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14887539445.webp', 'https://www.flickr.com/photos/zaragozaantigua/14887539445/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23352, 'Pasarela sobre el Canal 1925', 'AHPZ. Archivo Fotogr‚îú√≠fico Julio Requejo. 20/03/1925. "El Canal." La ribera del Canal, con visual de la pasarela peatonal que conduc‚îú¬°a a la calle de Venecia, actual de Ruiz Tapiador, en en hom‚îú‚îÇnimo barrio. Al fondo, a la derecha, el embarcadero del Canal. M‚îú√≠s adelante, el puente de Am‚îú¬Ærica. La pasarela ser‚îú√≠ desmontada d‚îú¬Æcadas m‚îú√≠s tarde, y sustituida por un puente para coches.', 1925, 1925, 1925, 'Anos 20', 'TORRERO', 41.63373500, -0.88853500, '0101000020E6100000573ECBF3E06EECBF50AA7D3A1ED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14937388472.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14937388472.webp', 'https://www.flickr.com/photos/zaragozaantigua/14937388472/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23372, 'Iglesia de San Fernando 1833', '"Yglesia de Torrero tomada desde la torre de Torrero", litograf‚îú¬°a de Faramundo Blanchard. Iglesia de San Fernando. Fuente visual: "Memoria hist‚îú‚îÇrica del Canal imperial de Aragon: noticia sobre las utilidades que produce, y esplicacion de lo que contienen las l‚îú√≠minas que se publican", Madrid, 1833.', 1833, 1833, 1833, 'Siglo XIX', 'TORRERO', 41.63465600, -0.88291900, '0101000020E6100000768BC058DF40ECBFE71A66683CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20162705268.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20162705268.webp', 'https://www.flickr.com/photos/zaragozaantigua/20162705268/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23374, 'Iglesia de San Fernando 1833', '"Yglesia de Torrero tomada desde el paseo de la Puyade", litograf‚îú¬°a de Faramundo Blanchard. Iglesia de San Fernando, vista desde el camino de Lapuyade. Fuente visual: "Memoria hist‚îú‚îÇrica del Canal imperial de Aragon: noticia sobre las utilidades que produce, y esplicacion de lo que contienen las l‚îú√≠minas que se publican", Madrid, 1833.', 1833, 1833, 1833, 'Siglo XIX', 'TORRERO', 41.63465600, -0.88291900, '0101000020E6100000768BC058DF40ECBFE71A66683CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20164136529.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20164136529.webp', 'https://www.flickr.com/photos/zaragozaantigua/20164136529/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23375, 'Torre de Pina c.1923', 'Imagen de la verja de forja del gran frontal de la torre de Pina al Canal Imperial. Fuente visual: amable aportaci‚îú‚îÇn de Federico Infante Pina.', 1923, 1923, 1923, 'Anos 20', 'TORRERO', 41.63283700, -0.88049400, '0101000020E61000000B60CAC0012DECBF715985CD00D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20274571818.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20274571818.webp', 'https://www.flickr.com/photos/zaragozaantigua/20274571818/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23380, 'Canal Imperial 1933', 'Canal Imperial de Arag‚îú‚îÇn y puente de Am‚îú¬Ærica. A la izquierda, el cuartel de Castillejos. A la derecha, comienzo del barrio de Torrero. Al fondo, la Torre de Pina. Fuente visual: Foto Conrado Barl‚îú¬Æs, donada por Daniel Barl‚îú¬Æs y digitalizada por Jos‚îú¬Æ Luis Cintora para www.rafaelcastillejo.com', 1933, 1933, 1933, 'Anos 30', 'TORRERO', 41.63330200, -0.88454900, '0101000020E610000042B456B4394EECBFE63E390A10D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22615634643.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22615634643.webp', 'https://www.flickr.com/photos/zaragozaantigua/22615634643/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23385, 'Canal Imperial 1861', 'Vista del Canal Imperial de Arag‚îú‚îÇn, con el puente de Am‚îú¬Ærica y el dique de carena o d‚îú√≠rsena del puerto de Miraflores en el centro de la imagen. Fuente: Mariano J‚îú‚ïëdez y Ortiz. ‚îú√ºlbum de Andr‚îú¬Æs Mart‚îú¬°n e Ip‚îú√≠s. Colecci‚îú‚îÇn Mariano Mart‚îú¬°n Casalderrey. Libro Primeros tiempos de la fotograf‚îú¬°a en Zaragoza', 1861, 1861, 1861, 'Siglo XIX', 'TORRERO', 41.63334900, -0.88432500, '0101000020E61000005C2041F1634CECBF27FA7C9411D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28299918210.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28299918210.webp', 'https://www.flickr.com/photos/zaragozaantigua/28299918210/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23389, 'Canal Imperial a‚îú‚ñíos 30', '"G‚îú‚îÇndola del Canal Imperial", acuarela de Ambrosio Ruste que representa una de las embarcaciones de sirga del Canal Imperial de Arag‚îú‚îÇn, en las inmediaciones de la playa de Torrero. Fuente: L‚îú√≠minas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'TORRERO', 41.63309900, -0.88354300, '0101000020E6100000E48233F8FB45ECBFAE10566309D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32062739540.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32062739540.webp', 'https://www.flickr.com/photos/zaragozaantigua/32062739540/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23492, 'Cuartel de Torrero 1923', 'In‚îú¬Ædita imagen capturada junto al ingreso al cuartel de caballer‚îú¬°a de Torrero ubicado junto a la playa de Torrero o paseo de Am‚îú¬Ærica, donde un soldado hace la guardia. Al fondo y tras la plaza de las Terrazas, la imponente fachada de la Torre de D‚îú√≠maso Pina, cuyo gran torre‚îú‚îÇn esquinero queda levemente oculto tras los pl‚îú√≠tanos de sombra de la derecha, inmediatos al cauce del Canal Imperial de Arag‚îú‚îÇn.', 1923, 1923, 1923, 'Anos 20', 'TORRERO', 41.63318200, -0.88169500, '0101000020E6100000BB7EC16ED836ECBF3B35971B0CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51285595655.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51285595655.webp', 'https://www.flickr.com/photos/zaragozaantigua/51285595655/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23650, 'Playa de Torrero c.1900', 'Imagen, hacia 1900, de la denominada "playa de Torrero", o ribera izquierda del Canal Imperial en su tramo entre el puente de Am‚îú¬Ærica y el arranque de la acequia de Ontonar, con las instalaciones y pabellones del antiguo e ilustrado complejo del "Puerto de Miraflores". Una parte de ellas hab‚îú¬°a sido militarizada en 1854, cuando comenzaron a ser utilizadas como cuartel de tropas de infanter‚îú¬°a. En 1866 se oficializa la entrega al Ramo de Guerra de fincas y edificios antes pertenecientes al Canal Imperial de Arag‚îú‚îÇn. Hoy la cosa sigue igual. En la ‚îú¬Æpoca de esta imagen, aqu‚îú¬° se alojaba el Regimiento de Lanceros del Rey (1‚î¨‚ïë de Caballer‚îú¬°a). La iglesia neocl‚îú√≠sica de San Fernando, con su c‚îú‚ïëpula y torres gemelas, que seg‚îú‚ïën los entendidos es de lo mejor de la ciudad en este estilo, tambi‚îú¬Æn fue transferida al brazo militar. Fuente visual: mdc.cbuc.cat,', 1900, 1900, 1900, 'Anos 1900', 'TORRERO', 41.63363900, -0.88437700, '0101000020E6100000FAB48AFED04CECBF2E3C2F151BD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20038187349.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20038187349.webp', 'https://www.flickr.com/photos/zaragozaantigua/20038187349/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23651, 'Mill‚îú√≠n Astray 1936', 'Imagen del general Mill‚îú√≠n Astray en el cuartel de caballer‚îú¬°a de Castillejos, acto programado durante su visita del 26 de agosto de ese a‚îú‚ñío, dentro de una ronda de visitas de altos jerarcas golpistas a las principales ciudades sublevadas. Lleg‚îú‚îÇ en tren a la Estaci‚îú‚îÇn del Norte, donde hubo una concentraci‚îú‚îÇn popular y fue recibido formalmente por las nuevas autoridades locales. Fue a la sede de la "Legi‚îú‚îÇn Navarro-Aragonesa" de Requet‚îú¬Æs. Pase‚îú‚îÇ por el Mercado Central. Visit‚îú‚îÇ heridos en el Hospital Militar. Ya en Castllejos, inspeccion‚îú‚îÇ las fuerzas de caballer‚îú¬°a y falangistas all‚îú¬° acuartelados. En la imagen, el general inspecciona a las milicias femeninas de Falange, acompa‚îú‚ñíado por el Jefe Local, Jes‚îú‚ïës Muro Sevilla (brazo en alto y gafas de sol), que unos meses despu‚îú¬Æs fundar‚îú¬°a "Radio Zaragoza". Mill‚îú√≠n Astray realiz‚îú‚îÇ tambi‚îú¬Æn una alocuci‚îú‚îÇn radiada donde defini‚îú‚îÇ la Zaragoza de la Nueva Espa‚îú‚ñía: "Zaragoza es Zaragoza. Zaragoza es Espa‚îú‚ñía. Es Agustina de Arag‚îú‚îÇn. Es Palafox. Es la Nobleza, el Honor, la Bravura, la Honradez. Zaragoza es, mientras el mundo sea mundo, la Virgen del Pilar". Fuente: Foto Lozano, Archivo Campos, "La guerra civil en Arag‚îú‚îÇn", ed. Delsan, 2010', 1936, 1936, 1936, 'Anos 30', 'TORRERO', 41.63440100, -0.88400200, '0101000020E6100000AA27F38FBE49ECBF5CC64D0D34D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20240331878.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20240331878.webp', 'https://www.flickr.com/photos/zaragozaantigua/20240331878/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23653, 'San Fernando 1947', 'Imagen de la iglesia de San Fernando, en zona militar del cuartel de Torrero, pero a‚îú‚ïën con el per‚îú¬°metro del murete que la delimitaba como no castrense. Fuente: Instituto Amatller de Arte Hisp‚îú√≠nico (Arxiu Mas).', 1947, 1947, 1947, 'Anos 40', 'TORRERO', 41.63465600, -0.88291900, '0101000020E6100000768BC058DF40ECBFE71A66683CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20356706852.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20356706852.webp', 'https://www.flickr.com/photos/zaragozaantigua/20356706852/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23654, 'Castillejos 1936', '18 de julio 1936. Voluntarios fascistas, falangistas, requet‚îú¬Æs, de Renovaci‚îú‚îÇn Espa‚îú‚ñíola y Juventudes de Acci‚îú‚îÇn Popular, congregados en el patio del Cuartel de Castillejos, entre el Playa de Torrero. Constituir‚îú√≠n el brazo paramilitar de la V‚î¨‚ïë Divisi‚îú‚îÇn org‚îú√≠nica del ej‚îú¬Ærcito que en Zaragoza se sublev‚îú‚îÇ y respald‚îú‚îÇ el golpe de Estado contra la Rep‚îú‚ïëblica democr‚îú√≠tica. Organizados en patrullas, estos civiles armados recorrer‚îú√≠n las calles, vigilar‚îú√≠n las barriadas "m‚îú√≠s peligrosas", y actuar‚îú√≠n como fuerzas del "nuevo orden" impuesto. Fuente visual: "Historia de la Cruzada espa‚îú‚ñíola", 1941.', 1936, 1936, 1936, 'Anos 30', 'TORRERO', 41.63440100, -0.88400200, '0101000020E6100000AA27F38FBE49ECBF5CC64D0D34D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20395483756.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20395483756.webp', 'https://www.flickr.com/photos/zaragozaantigua/20395483756/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23656, 'Cuartel Castillejos 1973', 'Aspecto del cuartel de Castillejos ante su inminente derribo para reconvertirlo en cuartel de San Fernando. Fuente: Diario Amanecer, 1973.', 1973, 1973, 1973, 'Anos 70', 'TORRERO', 41.63393500, -0.88354200, '0101000020E6100000CE8E54DFF945ECBF176536C824D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21191299905.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21191299905.webp', 'https://www.flickr.com/photos/zaragozaantigua/21191299905/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23659, 'Cuartel de Torrero 1917', 'Proyecto de deslinde de edificios y terrenos de Torrero entre los ramos de Guerra y de Fomento, Zaragoza, 12 de marzo de 1917. Fuente: www.asociacionlossitios.com/iglesia%20de%20San%20Fernando...', 1917, 1917, 1917, 'Anos 10', 'TORRERO', 41.63393500, -0.88354200, '0101000020E6100000CE8E54DFF945ECBF176536C824D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23852954203.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23852954203.webp', 'https://www.flickr.com/photos/zaragozaantigua/23852954203/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23665, 'Cuartel de Castillejos 1968', 'Imagen del multitudinario acto organizado durante la peregrinaci‚îú‚îÇn cat‚îú‚îÇlica de personas de la comunidad europea gitana que confluy‚îú‚îÇ en Zaragoza en 1968. El nocturno mitin se desarrolla en el gran patio central del cuartel de Castillejos, y el edificio del fondo era el ala recayente al paseo de Cu‚îú¬Ællar. Presente en la ceremonia, el arzobispo de la archidi‚îú‚îÇcesis de Zaragoza, Pedro Cantero Cuadrado. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1968, 1968, 1968, 'Anos 60', 'TORRERO', 41.63440100, -0.88400200, '0101000020E6100000AA27F38FBE49ECBF5CC64D0D34D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29958869770.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29958869770.webp', 'https://www.flickr.com/photos/zaragozaantigua/29958869770/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23683, 'Cuartel de Castillejos 1952', 'Imagen capturada desde la altura de la torre del Sacrario Militare y orientada hacia el sureste urbano. En primer t‚îú¬Ærmino y a la izquierda, el cuartel de Castillejos, la antigua playa de Torrero y tramo del Canal Imperial de Arag‚îú‚îÇn entre el Puente de Am‚îú¬Ærica y la curva hacia el Cabezo Cortado. Hacia el fondo destaca la gran estructura fabril de Alumalsa, donde la barriada de Col‚îú‚îÇn. Al otro lado del Canal, viveros municipales e instalaciones de la Confederaci‚îú‚îÇn Hidrogr‚îú√≠fica del Ebro. Hacia el fondo y a la derecha, vista parcial de la moderna grada del campo de f‚îú‚ïëtbol de Torrero.', 1952, 1952, 1952, 'Anos 50', 'TORRERO', 41.63363900, -0.88437700, '0101000020E6100000FAB48AFED04CECBF2E3C2F151BD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48904379856.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48904379856.webp', 'https://www.flickr.com/photos/zaragozaantigua/48904379856/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23684, 'V‚îú¬°a de San Fernando 1952', 'Cerramos el ciclo de vistas capturadas desde la altura de la torre del Sacrario Militare que iniciamos el pasado d‚îú¬°a 15, con esta imagen orientada hacia el sureste urbano. En primer t‚îú¬Ærmino, pabellones del cuartel de Caballer‚îú¬°a de los Castillejos, o de Torrero, recayentes al paseo de Cu‚îú¬Ællar. A la izquierda, la V‚îú¬°a de San Fernando, abierta en terrenos del Canal Imperial de Arag‚îú‚îÇn y que no fue considerada "calle" hasta un buen pu‚îú‚ñíado de a‚îú‚ñíos m‚îú√≠s tarde, al no estar completamente urbanizada, ni contar con m‚îú√≠s viviendas en el lado norte, o frente al cuartel, que las traseras de antiguas "torres". Hacia la izquierda y paralela a esta v‚îú¬°a, en una terraza inferior, la calle de Lapuyade, por donde pasara el antiguo camino de la Caba‚îú‚ñíera. Hacia el fondo, caser‚îú¬°o del barrio de San Jos‚îú¬Æ donde destaca el regular trazado del Grupo de viviendas Puente Virrey-Rosell‚îú‚îÇn, la antigua Granja Agr‚îú¬°cola y el gran complejo de la cementera de Miraflores. A la izquierda extrema, Villa Asunci‚îú‚îÇn. Vertebra la imagen, en el centro, la neocl‚îú√≠sica iglesia de San Fernando, de forzado uso castrense. A la derecha y tras el cuartel, talleres del Canal Imperial de Arag‚îú‚îÇn, el colegio de La Salle de Torrero, y la gran casa de D‚îú√≠maso Pina.', 1952, 1952, 1952, 'Anos 50', 'TORRERO', 41.63440100, -0.88400200, '0101000020E6100000AA27F38FBE49ECBF5CC64D0D34D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48927463893.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48927463893.webp', 'https://www.flickr.com/photos/zaragozaantigua/48927463893/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24850, 'Mu‚îú‚ñíoz Grandes 1979', 'Imagen de lo que fue la celebrada "Terraza de Pina" junto al Canal Imperial como inexcusable jal‚îú‚îÇn visual entre el recuerdo de la "playa de Torrero" y el camino que conduc‚îú¬°a a la festiva Quinta de Sagols. La denominaci‚îú‚îÇn de este lugar fue mutando a simplemente "La Terraza", luego "Plaza Terraza", y a finales de los a‚îú‚ñíos 70 del pasado siglo, cuando las casas de Pina fueron sustituidas por las colmenas habitacionales que hoy hay, la plaza recibi‚îú‚îÇ la denominaci‚îú‚îÇn "General Mu‚îú‚ñíoz Grandes" (part‚îú¬°cipe de la "Cruzada contra el bolchevismo", y previsto sucesor de Franco), y en ella se estableci‚îú‚îÇ una parada de la l‚îú¬°nea 23 de los autobuses urbanos, cuando su trayecto era Barrio de la Paz-Plaza de San Miguel, y por esta plaza se consegu‚îú¬°a la mejor conexi‚îú‚îÇn con la avenida de San Jos‚îú¬Æ para ir al "centro". En los bajos de los nuevos bloques fue instalado, adem‚îú√≠s, un consultorio p‚îú‚ïëblico de atenci‚îú‚îÇn primaria. En 2003, la plaza fue redenominada del Canal Imperial de Arag‚îú‚îÇn. En la imagen, a la derecha, parte de las instalaciones de la CHE y, fuera de plano, lo que fuera hasta 1974 el colegio de "La Salle Torrero". Al fondo, el Canal Imperial y el paseo hasta el puente de Am‚îú¬Ærica. Hacia la izquierda, la carretera conduce a la f‚îú√≠brica ALUMALSA, a las graveras de la Paz, y al Cabezo Cortado.', 1979, 1979, 1979, 'Anos 70', 'TORRERO', 41.63291100, -0.88093200, '0101000020E6100000F4FE3F4E9830ECBFAB23473A03D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22917157435.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22917157435.webp', 'https://www.flickr.com/photos/zaragozaantigua/22917157435/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25004, 'Pasarela Venecia c.1912', 'Imagen convertida en postal por la Fototipia Thomas, de Barcelona, como n‚îú‚ïëmero 21 de la serie titulada "Zaragoza", con el t‚îú¬°tulo "Puente de Venecia sobre el Canal". Se trata de la pasarela peatonal instalada sobre el Canal Imperial a la altura de la calle de Venecia (orilla derecha), y la torre de Julia Arpal (orilla izquierda). La imagen est‚îú√≠ tomada desde la orilla derecha, de forma que permite una interesante visual de la arbolada orilla izquierda, con huertos y cultivos tras el paseo del Canal. Al fondo y la izquierda, la f‚îú√≠brica de harinas "La Imperial de Arag‚îú‚îÇn". Fuente visual: Colecci‚îú‚îÇn Jos‚îú¬Æ Luis Cintora.', 1912, 1912, 1912, 'Anos 10', 'TORRERO', 41.63373500, -0.88853500, '0101000020E6100000573ECBF3E06EECBF50AA7D3A1ED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24354026864.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24354026864.webp', 'https://www.flickr.com/photos/zaragozaantigua/24354026864/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25011, 'P.‚î¨‚ïë de los Ruise‚îú‚ñíores 1931', 'Luminosa e in‚îú¬Ædita imagen del Colegio Mayor de Cerbuna de la Universidad de Zaragoza, sito en el n‚îú‚ïëmero 23 del paseo de los Ruise‚îú‚ñíores (por donde se acced‚îú¬°a a la izquierda de la foto), capturada desde la pista del inmediato front‚îú‚îÇn que formaba parte de las instalaciones deportivas de este recinto universitario. En la "fachada del mediod‚îú¬°a" que centra la escena destaca a la izquierda el rotundo torre‚îú‚îÇn que permit‚îú¬°a unas vistas muy apreciables y en el que ya figura el r‚îú‚îÇtulo identificativo del edificio que fue instalado tras su inauguraci‚îú‚îÇn. Este Colegio Mayor de Cerbuna era una instituci‚îú‚îÇn oficial dependiente de la Universidad de Zaragoza que funcionaba de acuerdo con el Real decreto de 24 de agosto de 1926, Real orden de 28 de abril de 1927 y las disposiciones del Consejo de Patronato y Junta de gobierno de la Universidad. Estaba destinada a LOS estudiantes de todas las facultades universitarias de Zaragoza. Fue construido sobre la antigua Torre de Conti seg‚îú‚ïën proyecto del arquitecto Teodoro R‚îú¬°os Balaguer que imitaba la traza de la Residencia de Estudiantes de Madrid. Por ello, esta instituci‚îú‚îÇn era conocida de forma no oficial como "Residencia de Estudiantes de la Universidad de Zaragoza" o "Residencia Universitaria". Inaugurado oficialmente el 26 de febrero de 1925 por el rey Alfonso XIII, fue clausurado en 1936. En los a‚îú‚ñíos 60 fue derribado y sobre su solar se construy‚îú‚îÇ el nuevo Instituto Femenino Miguel Servet, que con proyecto del arquitecto Regino Borobio Ojeda fue inaugurado en 1965.', 1931, 1931, 1931, 'Anos 30', 'TORRERO', 41.63532000, -0.88995600, '0101000020E610000092205C01857AECBF533F6F2A52D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53158462367.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53158462367.webp', 'https://www.flickr.com/photos/zaragozaantigua/53158462367/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25013, 'P.‚î¨‚ïë de los Ruise‚îú‚ñíores 1931', 'In‚îú¬Ædita imagen capturada en el interior de uno de los 37 dormitorios de que constaba la Residencia de Estudiantes o Colegio Mayor de Cerbuna de la Universidad de Zaragoza, para otros tantos alumnos residentes. Comprende cama, mesilla, mesa para escribir, dos sillas, lavabo de agua corriente fr‚îú¬°a y caliente, espejo biselado, armario ropero, l‚îú√≠mpara de luz el‚îú¬Æctrica en el techo y flexo en la mesa de escribir, timbre y calefacci‚îú‚îÇn.', 1931, 1931, 1931, 'Anos 30', 'TORRERO', 41.63532000, -0.88995600, '0101000020E610000092205C01857AECBF533F6F2A52D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53183461548.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53183461548.webp', 'https://www.flickr.com/photos/zaragozaantigua/53183461548/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25184, 'La Balseta, 1978', 'Portada del programa de fiestas del barrio de San Jos‚îú¬Æ con un dibujo de Carlos Mar‚îú¬°n que recordaba en sus ‚îú‚ïëltimos tiempos el antiguo lavadero de la Balseta, derribado unos pocos a‚îú‚ñíos antes. Aqu‚îú¬° es representado idealmente en su ubicaci‚îú‚îÇn desde finales del siglo XVIII al final de la actual avenida de San Jos‚îú¬Æ. Al fondo, inmueble del "Molino Rosa" y colegio de La Salle "Torrero" en el barrio de San Jos‚îú¬Æ.', 1978, 1978, 1978, 'Anos 70', 'TORRERO', 41.63429700, -0.88154500, '0101000020E610000068791EDC9D35ECBFB779E3A430D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50915445257.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50915445257.webp', 'https://www.flickr.com/photos/zaragozaantigua/50915445257/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25190, 'C.‚î¨‚ïë de San Jos‚îú¬Æ 1891', 'Dibujo centrado en el lugar denominado "las cuatro esquinas" sito en la parte alta del arbolado camino de San Jos‚îú¬Æ, al objeto de ilustrar el "teatro del crimen" donde fue hallado el cad‚îú√≠ver del industrial tronchonero Felipe Conesa, asesinado el 30 de diciembre de 1890, en lo que la prensa de la ‚îú¬Æpoca titul‚îú‚îÇ de forma sensacionalista, para hacer a‚îú‚ïën m‚îú√≠s atractivo este escabroso suceso, como "el crimen del sombrerero", ya que aqu‚îú¬° se encontraba la f‚îú√≠brica del sombreros que regentaba el finado. A la derecha, el horno-bodeg‚îú‚îÇn de Braulio Moreno que esquinaba con el camino de Lapuyade o de la Caba‚îú‚ñíera. Al fondo, despejado espacio donde destacaba el lavadero de la Balseta nutrido por la acequia del Plano, con el fondo de las extensas instalaciones del cuartel del regimiento cazadores de los Castillejos (18.‚î¨‚ïë de Caballer‚îú¬°a), que el Ramo de la Guerra ocupaba en terrenos originalmente propiedad del Canal Imperial de Arag‚îú‚îÇn. En la ‚îú¬Æpoca del suceso referido, este fue tambi‚îú¬Æn denominado como el "crimen de Torrero", aunque a los actuales vecinos de este barrio les sorprender‚îú¬°a saber que en entonces el barrio de Triana, sito entre el camino de las Canteras y el camino del Cementerio, segu‚îú¬°a siendo el pionero n‚îú‚ïëcleo habitado del actual barrio de Torrero.', 1891, 1891, 1891, 'Siglo XIX', 'TORRERO', 41.63461900, -0.88078200, '0101000020E6100000A0F99CBB5D2FECBFCA3505323BD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54152892780.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54152892780.webp', 'https://www.flickr.com/photos/zaragozaantigua/54152892780/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25727, '&quot;La Balseta&quot; 1990', 'Al final de la avenida de San Jos‚îú¬Æ, arriba del todo, veinte a‚îú‚ñíos antes hab‚îú¬°a acontecido el derribo del lavadero de "La Balseta", ese "mamotreto feo y molesto" seg‚îú‚ïën la prensa del momento, que es la misma que la de ahora, porque molestaba al progreso desarrollista de la ciudad, y como llevaba d‚îú¬Æcadas abandonado, estaba en muy malas condiciones: la tormenta perfecta. El objeto era liberar espacio para la circulaci‚îú‚îÇn rodada, pura y simplemente. El resultado tras el derribo, del que la imagen es apenas un esbozo, atroz y destalentado. Bien se ve lo que molestaba la pervivencia del ‚îú‚ïëltimo lavadero p‚îú‚ïëblico de la ciudad. En este entorno bien poco amable, perduraban a la izquierda las parcelitas del final de la calle de Lapuyade, antes de su derribo. A la derecha, las viviendas del "Molino Rosa", en referencia a los dieciochescos molinos de harina y de aceite all‚îú¬° instalados cuando la obra del Canal Imperial. A‚îú‚ñíos despu‚îú¬Æs tambi‚îú¬Æn derribadas, para moderno crecimiento vertical. En el centro de la imagen, sobresaliente en altura, el silo de SAPASA junto a la Harinera de Mor‚îú‚îÇn, tambi‚îú¬Æn derribado. El aparcamiento en superficie all‚îú√≠ donde hubiera, o hubiese sitio, signo de los tiempos. Fuente visual: Archivo Enrique Baile.', 1990, 1990, 1990, 'Anos 90', 'TORRERO', 41.63428900, -0.88155600, '0101000020E610000062F6B2EDB435ECBF359BC76130D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20121308078.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20121308078.webp', 'https://www.flickr.com/photos/zaragozaantigua/20121308078/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25735, 'Iglesia de San Fernando 1988', 'Foto Eduardo Zamarripa, 1988. Vista a‚îú¬Ærea de la Iglesia de San Fernando de Zaragoza en 1988. Fuente: Arag‚îú‚îÇn desde el aire, Ministerio de Defensa, 1988.', 1988, 1988, 1988, 'Anos 80', 'TORRERO', 41.63465600, -0.88291900, '0101000020E6100000768BC058DF40ECBFE71A66683CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20292742266.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20292742266.webp', 'https://www.flickr.com/photos/zaragozaantigua/20292742266/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25736, 'San Fernando 1844', '"Iglesia en Monte Torrero". Estamos en el entorno de la Playa de Torrero. Unos pocos a‚îú‚ñíos despu‚îú¬Æs (1852) comenzar‚îú¬°an las presiones al Gobernador Civil, por parte del Capit‚îú√≠n General de Arag‚îú‚îÇn, para convertir las instalaciones del Canal Imperial en la Playa como cuartel del Ej‚îú¬Ærcito. Progresivamente se fue consumando la ocupaci‚îú‚îÇn, mientras la autoridad del Canal solicitaba en vano su devoluci‚îú‚îÇn, hasta que en 1930 se legaliz‚îú‚îÇ esta ocupaci‚îú‚îÇn por representantes del Canal, del Ayuntamiento y del ramo de la Guerra. Quedaron s‚îú‚îÇlo como lugar de tr‚îú√≠nsito p‚îú‚ïëblico una calleja transversal que enlazaba el camino de la Iglesia de San Fernando con la Playa de Torrero. La Iglesia de San Fernando, una obra emblem‚îú√≠tica de la f‚îú√≠brica del Canal Imperial, y destacado ejemplo de la escasa arquitectura neocl‚îú√≠sica en Zaragoza, qued‚îú‚îÇ dentro de la jurisdicci‚îú‚îÇn militar. Hasta hoy. Fuente visual: "Recuerdos y Bellezas de Espa‚îú‚ñía. Obra destinada a dar a conocer sus monumentos, antig‚îú‚ïùedades y vistas pintorescas en l‚îú√≠minas dibujadas del natural y litografiadas por F. J. Parcerisa, acompa‚îú‚ñíadas de texto por P. Piferrer y J. M. Quadrado. Arag‚îú‚îÇn: Jos‚îú¬Æ Mar‚îú¬°a Quadrado. 1844."', 1844, 1844, 1844, 'Siglo XIX', 'TORRERO', 41.63465600, -0.88291900, '0101000020E6100000768BC058DF40ECBFE71A66683CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20293993316.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20293993316.webp', 'https://www.flickr.com/photos/zaragozaantigua/20293993316/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25741, 'San Fernando 1845', '"Vista de Torrero desde el paseo de la Puya", dibujo acuarelado respecto del original incluido en la obra "Espa‚îú‚ñía Geografica, Historica, Estadistica y Pintoresca", de Francisco de Paula Mellado. En la imagen, la iglesia de San Fernando desde la actual calle Lapuyade. Fuente visual: www.frame.es/', 1845, 1845, 1845, 'Siglo XIX', 'TORRERO', 41.63465600, -0.88291900, '0101000020E6100000768BC058DF40ECBFE71A66683CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20326898301.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20326898301.webp', 'https://www.flickr.com/photos/zaragozaantigua/20326898301/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25744, 'Vista de Cu‚îú¬Ællar c.1950', 'Imagen en altura desde la torre del mausoleo de San Antonio, con una vista irrepetible del tramo del paseo de Cu‚îú¬Ællar vecino del parque de Pignatelli. Hacia la derecha, las calles de Vista Alegre, Pradilla, Lapuyade... con las parcelas y hotelitos del antiguo "Barrio de los Chiflaos", o de las Acacias. Un tranv‚îú¬°a va de bajada, y otro de subida, en la l‚îú¬°nea de Torrero. Al fondo, el enorme edificio de los PP. Agustinos, en el camino de las Torres, las huertas de Miraflores, hasta llegar a la enorme torre del "Gas". Al fondo, a la izquierda, la vieja ciudad. Fuente: "Los tranv‚îú¬°as de Zaragoza", J. Pe‚îú‚ñía - J. M. Valero, DPZ, 1985.', 1950, 1950, 1950, 'Anos 50', 'TORRERO', 41.63487900, -0.88480800, '0101000020E610000044A7E7DD5850ECBF66F50EB743D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20378868196.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20378868196.webp', 'https://www.flickr.com/photos/zaragozaantigua/20378868196/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25748, 'Vista Cu‚îú¬Ællar 1968', 'Imagen a‚îú¬Ærea del entorno del Paseo de Cu‚îú¬Ællar en su tramo final, desde el Parque de Pignatelli hasta la antigua Playa de Torrero. Fuente visual: AVV. San Jos‚îú¬Æ.', 1968, 1968, 1968, 'Anos 60', 'TORRERO', 41.63487900, -0.88480800, '0101000020E610000044A7E7DD5850ECBF66F50EB743D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20402315711.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20402315711.webp', 'https://www.flickr.com/photos/zaragozaantigua/20402315711/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25754, 'Sacrario Militare 1947', 'Imagen de las traseras del santuario "Sacrario Militare Italiano" inaugurado en 1945 sobre terrenos que fueran jardines y planteros del Canal Imperial, junto a la acequia del Plano, muy cerca de la Almenara de Santa Engracia. Formaban parte de este nuevo y enorme complejo el convento de los PP. Franciscanos Capuchinos, la iglesia de San Antonio de Padua, y el mausoleo a la memoria de los combatientes legionarios de la Italia de Mussolini. En 1965, el arzobispo Cantero Cuadrado segreg‚îú‚îÇ esta iglesia, y la convirti‚îú‚îÇ en parroquia independiente para atender a la creciente grey de la zona. A la izquierda, vista parcial de la iglesia de San Fernando, y de uno de los pabellones del antiguo Cuartel de los Castillejos, al otro lado del paseo de Cu‚îú¬Ællar. Fuente: Archivo Enrique Baile.', 1947, 1947, 1947, 'Anos 40', 'TORRERO', 41.63469100, -0.88530900, '0101000020E6100000C5573B8A7354ECBF6308008E3DD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21572060735.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21572060735.webp', 'https://www.flickr.com/photos/zaragozaantigua/21572060735/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25756, 'Vista a‚îú¬Ærea Cu‚îú¬Ællar c.1990', 'Foto: Archivo Taumar (Irene Taul‚îú¬Æs y Rafael Margal‚îú¬Æ). Vista a‚îú¬Ærea del entorno comprendido entre el Canal Imperial (abajo) y los dep‚îú‚îÇsitos de agua de Pignatelli (arriba). A la derecha, iglesia de San Antonio de Padua. En el centro, el enorme complejo del hom‚îú‚îÇnimo colegio cat‚îú‚îÇlico financiado por el Estado. Fuente visual: www.facebook.com/photo.php?fbid=1692384257651940&set=...', 1990, 1990, 1990, 'Anos 90', 'TORRERO', 41.63462400, -0.88662100, '0101000020E6100000514CDE00335FECBFDCA0F65B3BD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22887483570.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22887483570.webp', 'https://www.flickr.com/photos/zaragozaantigua/22887483570/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25757, 'Paseo del Canal 1968', 'En 1965, la jerarqu‚îú¬°a eclesi‚îú√≠stica cat‚îú‚îÇlica organiz‚îú‚îÇ una peregrinaci‚îú‚îÇn para, desde diferentes pa‚îú¬°ses de la Europa occidental, hacer afluir a Roma un n‚îú‚ïëmero importante de personas de etnia gitana, durante el pontificado de Pablo VI. A partir de ese a‚îú‚ñío, y hasta 1971, la peregrinaci‚îú‚îÇn continu‚îú‚îÇ teniendo lugar en Francia, Alemania Occidental, Espa‚îú‚ñía, B‚îú¬Ælgica, Portugal, y nuevamente Francia. En 1968, la cita fue en Zaragoza, y el evento fue un gran acontecimiento social, con su parte vinculada a ritos, iconos, creencias y ceremoniales cat‚îú‚îÇlicos (muy publicitada en medios de comunicaci‚îú‚îÇn de la ‚îú¬Æpoca), con la particular interpretaci‚îú‚îÇn que de los mismos hace esta comunidad ‚îú¬Ætnica, y con otra parte muy importante vinculada a algunas caracter‚îú¬°sticas del nomadismo de los participantes (visita a familiares lejanos, acordar y concertar matrimonios, realizar transacciones y tratos...) En la imagen, aspecto del paseo del Canal como provisional camping habilitado para gitanas y gitanos venidos de otros lares durante esos d‚îú¬°as, a principios del mes de setiembre. Al fondo, la antigua torre de D‚îú√≠maso Pina. A la izquierda queda el Cuartel de Castillejos. A la derecha, el Canal Imperial. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1968, 1968, 1968, 'Anos 60', 'TORRERO', 41.63333400, -0.88388900, '0101000020E6100000A1698995D148ECBFF1B8A81611D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23363973321.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23363973321.webp', 'https://www.flickr.com/photos/zaragozaantigua/23363973321/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25760, 'Iglesia de San Fernando 1861', '"Vista de la iglesia neocl‚îú√≠sica construida bajo la direcci‚îú‚îÇn de Tiburcio del Caso en 1799, destinada a servir de parroquia a las familias que trabajaron en la construcci‚îú‚îÇn del Canal Imperial de Arag‚îú‚îÇn." Jos‚îú¬Æ Antonio Hern‚îú√≠ndez Latas. Fuente: Mariano J‚îú‚ïëdez y Ortiz. Colecci‚îú‚îÇn Antonio Arguas Perdiguer. Libro Primeros tiempos de la fotograf‚îú¬°a en Zaragoza.', 1861, 1861, 1861, 'Siglo XIX', 'TORRERO', 41.63465600, -0.88291900, '0101000020E6100000768BC058DF40ECBFE71A66683CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28299751290.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28299751290.webp', 'https://www.flickr.com/photos/zaragozaantigua/28299751290/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25781, 'Calle de Sancho Lezcano 1990', 'Imagen capturada en el principio de la calle de Sancho Lezcano y centrada en la fachada principal del n‚î¨‚ïë 1 con dependencias del Canal Imperial que albergaron los antiguos hornos de cocer pan y tahona de yeso del Canal Imperial. A la derecha, el angosto final de la avenida de San Jos‚îú¬Æ. Tras la parcela esquinera (n‚î¨‚ïë 3 de Sancho Lezcano) flu‚îú¬°a al aire la acequia del Ontonar, junto al recoleto espacio donde estuviera el lavadero de la Balseta y las casas del Molino Rosa (n‚î¨‚ïë 209-211 de la avenida de San Jos‚îú¬Æ). Al fondo emerge el moderno bloque del n‚î¨‚ïë 17 de la calle de Luis Royo Villanova. A‚îú‚ñíos despu‚îú¬Æs, la prolongaci‚îú‚îÇn de la avenida de San Jos‚îú¬Æ hasta el Canal Imperial reconfigurar‚îú√≠ radicalmente el urbanismo que caracterizaba esta zona. Fuente visual: colecci‚îú‚îÇn de Enrique Baile, en Gran Archivo Zaragoza Antigua (GAZA).', 1990, 1990, 1990, 'Anos 90', 'TORRERO', 41.63398600, -0.88211200, '0101000020E6100000C617EDF1423AECBF990F087426D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40754483474.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40754483474.webp', 'https://www.flickr.com/photos/zaragozaantigua/40754483474/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25783, 'Canal Imperial c.1895', 'In‚îú¬Ædita imagen capturada desde el ingreso a las casas de Salvador, luego de Pina, con vista a la derecha del arbolado ‚îú‚ïëltimo tramo de la playa de Torrero, inmediato a los almacenes y talleres del Canal Imperial. Al fondo se destaca el antiguo y peraltado puente de Am‚îú¬Ærica. A la izquierda, camino del Cabezo Cortado, y ya en la margen derecha, chopera en los viveros del Canal.', 1895, 1895, 1895, 'Siglo XIX', 'TORRERO', 41.63276500, -0.88154500, '0101000020E610000068791EDC9D35ECBFD7868A71FED04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48044024147.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48044024147.webp', 'https://www.flickr.com/photos/zaragozaantigua/48044024147/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26027, 'Cuartel de Castillejos 1975', 'Imagen capturada desde el Sacrario Militare Italiano durante las obras de construcci‚îú‚îÇn del nuevo Cuartel de Castillejos, ya como Centro Regional de Mando (CRM) del ej‚îú¬Ærcito de tierra. Entre las gr‚îú‚ïëas y los edificios de nueva planta, destaca la fagocitada y neocl‚îú√≠sica iglesia de San Fernando. A la izquierda, la V‚îú¬°a de San Fernando. En el centro destaca la nueva gran plaza que vertebra el acuartelamiento. Al fondo, el gran complejo edilicio donde estuviera la antigua torre de D‚îú√≠maso Pina, en la plaza del divisionario general Mu‚îú‚ñíoz Grandes. A la derecha, el paseo del Canal, en el punto donde estuviera el ilustrado puerto de Miraflores. Composici‚îú‚îÇn in‚îú¬Ædita, democr‚îú√≠tica, cient‚îú¬°fica y popular, generada en los laboratorios del', 1975, 1975, 1975, 'Anos 70', 'TORRERO', 41.63440100, -0.88400200, '0101000020E6100000AA27F38FBE49ECBF5CC64D0D34D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30197544035.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30197544035.webp', 'https://www.flickr.com/photos/zaragozaantigua/30197544035/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26028, 'Parque Pignatelli 1963', 'Desde la demediada atalaya neomedieval del Sacrario Militare Italiano, un despejado vistazo en direcci‚îú‚îÇn norte para ver llenos y funcionales los antiguos dep‚îú‚îÇsitos de agua de Pignatelli, el Parque de Pignatelli, y la creciente cortina de nuevos bloques de viviendas en el final del paseo del General Mola, y en el arranque de los paseos de Cu‚îú¬Ællar, y de Ruise‚îú‚ñíores. En primer plano, la calle Maestro Estremiana. Al fondo, brumoso, el centro de la ciudad. Fuente visual: Gerardo Sancho Ramo, AMZ, ref. 14110', 1963, 1963, 1963, 'Anos 60', 'TORRERO', 41.63469100, -0.88530900, '0101000020E6100000C5573B8A7354ECBF6308008E3DD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30373099206.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30373099206.webp', 'https://www.flickr.com/photos/zaragozaantigua/30373099206/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23151, 'Monzalbarba 2009', 'Foto: V‚îú¬°ctor Lax. El Plan Espa‚îú‚ñíol para el Est‚îú¬°mulo de la Econom‚îú¬°a y el Empleo, "Plan E", pretendi‚îú‚îÇ aplacar la crisis econ‚îú‚îÇmica desde el Gobierno de Espa‚îú‚ñía, ofreciendo dinero a los ayuntamientos para obras p‚îú‚ïëblicas. En Zaragoza, la primera de estas obras (abril de 2009) fue la peatonalizaci‚îú‚îÇn de un callej‚îú‚îÇn del barrio rural de Monzalbarba: la calle del Arco, que vemos a la izquierda, partiendo de la de Santa Ana. Fuente: Heraldo de Arag‚îú‚îÇn.', 2009, 2009, 2009, 'Siglo XXI', 'MONZALBARBA', 41.70211200, -0.96914800, '0101000020E61000005B7B9FAA4203EFBF881057CEDED94440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32223072113.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32223072113.webp', 'https://www.flickr.com/photos/zaragozaantigua/32223072113/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23767, 'Crecida del Ebro 2003', 'Ortofoto de la crecida del r‚îú¬°o Ebro en febrero de 2003, centrada en el barrio rural de Monzalbarba. Fuente: Instituto Geogr‚îú√≠fico de Arag‚îú‚îÇn.', 2003, 2003, 2003, 'Siglo XXI', 'MONZALBARBA', 41.70211200, -0.96914800, '0101000020E61000005B7B9FAA4203EFBF881057CEDED94440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26604388057.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26604388057.webp', 'https://www.flickr.com/photos/zaragozaantigua/26604388057/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21627, 'San Juan de Mozarrifar 1923', '"Una calle de San Juan de Mozarrifar, despu‚îú¬Æs de la inundaci‚îú‚îÇn". Un grupo de ni‚îú‚ñíos posa en la calle de San Juan, en el barrio rural zaragozano de San Juan de Mozarrifar. Al fondo, la iglesia de San Juan Bautista o "iglesia vieja", del siglo XV y reformada en el XVIII y el XXI. La inundaci‚îú‚îÇn a que se refiere el encabezamiento es la de julio de 1923, por el desbordamiento del r‚îú¬°o G‚îú√≠llego.', 1923, 1923, 1923, 'Anos 20', 'SAN JUAN MOZARRIFAR', 41.71678100, -0.84013200, '0101000020E61000009B560A815CE2EABF74B2D47ABFDB4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/37524857810.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/37524857810.webp', 'https://www.flickr.com/photos/zaragozaantigua/37524857810/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24452, 'Papelera Las Navas 1913', 'Imagen del enorme conjunto fabril de la papelera de Las Navas en San Juan de Mozarrifar. En primer plano, la v‚îú¬°a de tren que conectaba la f‚îú√≠brica con la l‚îú¬°nea que proven‚îú¬°a de la Estaci‚îú‚îÇn del Norte. Durante la guerra 1936 1939, y aun durante tiempo despu‚îú¬Æs (hasta 1943), esta f‚îú√≠brica y sus alrededores fueron utilizados por los nacionalistas como campo de concentraci‚îú‚îÇn. En la actualidad, subsiste el edificio fabril de varios pisos, como taller mec‚îú√≠nico, sito en una zona industriosa de San Juan de Mozarrifar, en la calle Torre del Rosario.', 1913, 1913, 1913, 'Anos 10', 'SAN JUAN MOZARRIFAR', 41.71876600, -0.83298500, '0101000020E6100000B9DFA128D0A7EABF06BD378600DC4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15458511167.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15458511167.webp', 'https://www.flickr.com/photos/zaragozaantigua/15458511167/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
